const baseUrl = String($env.APP_VIDEO_OPS_BACKEND_BASE_URL || '').replace(/\/+$/, '');
const callbackSecret = String($env.APP_VIDEO_OPS_WORKFLOW_CALLBACK_SECRET || '');
const workflowRunId = Number($('Select Media (Scored)').item.json.workflowRunId || 0);
const contentIdeaId = $('Select Media (Scored)').item.json.id;
const shotstackRenderId = $('HTTP: Shotstack Render').item.json.response?.id || $('HTTP: Shotstack Render').item.json.id || '';

if (!baseUrl || !callbackSecret || !workflowRunId) {
  throw new Error('Missing callback config');
}

const body = JSON.stringify({
  status: 'SUCCEEDED',
  message: 'Professional render requested from Shotstack.',
  responsePayload: JSON.stringify({
    contentIdeaId,
    shotstackRenderId,
    mediaQuality: $('Select Media (Scored)').item.json.media_quality,
    mediaScore: $('Select Media (Scored)').item.json.media_score
  })
});

const http = require('http');
const https = require('https');
const { URL } = require('url');
const url = new URL(baseUrl + '/api/video-ops/workflow-runs/' + workflowRunId + '/complete');
const client = url.protocol === 'https:' ? https : http;

const response = await new Promise((resolve, reject) => {
  let attempts = 0;
  const maxAttempts = 3;

  const tryRequest = () => {
    const req = client.request({
      protocol: url.protocol,
      hostname: url.hostname,
      port: url.port || (url.protocol === 'https:' ? 443 : 80),
      path: url.pathname + url.search,
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Content-Length': Buffer.byteLength(body),
        'X-Video-Ops-Callback-Secret': callbackSecret,
        'X-Request-Timestamp': Date.now().toString()
      }
    }, (res) => {
      let data = '';
      res.on('data', (chunk) => { data += chunk; });
      res.on('end', () => resolve({ statusCode: res.statusCode || 0, body: data }));
    });

    req.on('error', (err) => {
      attempts++;
      if (attempts < maxAttempts) {
        setTimeout(tryRequest, Math.pow(2, attempts) * 1000);
      } else {
        reject(err);
      }
    });

    req.setTimeout(20000, () => {
      req.destroy();
      attempts++;
      if (attempts < maxAttempts) {
        setTimeout(tryRequest, Math.pow(2, attempts) * 1000);
      } else {
        reject(new Error('Callback timeout'));
      }
    });

    req.write(body);
    req.end();
  };

  tryRequest();
});

if (response.statusCode < 200 || response.statusCode >= 300) {
  throw new Error('Callback failed: ' + response.statusCode);
}

return [{ json: { ok: true, callbackStatusCode: response.statusCode } }];

const baseUrl = String($env.APP_VIDEO_OPS_BACKEND_BASE_URL || '').replace(/\/+$/, '');
const callbackSecret = String($env.APP_VIDEO_OPS_WORKFLOW_CALLBACK_SECRET || '');
